impl Solution { pub fn check_valid_cuts(n: i32, rectangles: Vec<Vec<i32>>) -> bool { let mut check = |idx: usize| { let mut black_h: Vec<(i32, i32)> = rectangles.iter().map(|r| (r[idx], r[idx+2])).collect(); black_h.sort_unstable(); let (mut black_cuts, mut black_end) = (0, black_h[0].1); for i in 1..black_h.len() { if black_h[i].0 >= black_end { black_cuts += 1; } black_end = black_end.max(black_h[i].1); } black_cuts >= 2 }; check(0) || check(1) } }